import{_ as a,o as e,c as d,ak as l}from"./chunks/framework.McRGG9h5.js";const g=JSON.parse('{"title":"TTHSD Next ABI 命名风格变更说明","description":"","frontmatter":{},"headers":[],"relativePath":"zh/ABI-Changing-Explan.md","filePath":"zh/ABI-Changing-Explan.md","lastUpdated":0}'),o={name:"zh/ABI-Changing-Explan.md"};function r(i,t,s,n,h,c){return e(),d("div",null,[...t[0]||(t[0]=[l(`<blockquote><p>本篇隶属于 <a href="/Bulletin/zh/overview.html">公告</a> 下</p></blockquote><h1 id="tthsd-next-abi-命名风格变更说明" tabindex="-1">TTHSD Next ABI 命名风格变更说明 <a class="header-anchor" href="#tthsd-next-abi-命名风格变更说明" aria-label="Permalink to “TTHSD Next ABI 命名风格变更说明”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>TTHSD Next（Rust 版本）在最近的更新中，对暴露的 C ABI 函数命名风格进行了变更：</p><table tabindex="0"><thead><tr><th>变更前（驼峰命名）</th><th>变更后（蛇形命名）</th></tr></thead><tbody><tr><td><code>getDownloader</code></td><td><code>get_downloader</code></td></tr><tr><td><code>startDownload</code></td><td><code>start_download</code></td></tr><tr><td><code>startDownload_ID</code></td><td><code>start_download_id</code></td></tr><tr><td><code>startMultipleDownloads_ID</code></td><td><code>start_multiple_downloads_id</code></td></tr><tr><td><code>pauseDownload</code></td><td><code>pause_download</code></td></tr><tr><td><code>resumeDownload</code></td><td><code>resume_download</code></td></tr><tr><td><code>stopDownload</code></td><td><code>stop_download</code></td></tr></tbody></table><h2 id="变更原因" tabindex="-1">变更原因 <a class="header-anchor" href="#变更原因" aria-label="Permalink to “变更原因”">​</a></h2><ol><li><p><strong>遵循 Rust 命名规范</strong>：Rust 语言默认使用 <code>snake_case</code> 作为函数命名风格，TTHSD Next 基于 Rust 开发，采用统一的命名风格更符合语言习惯。</p></li><li><p><strong>与底层实现一致</strong>：Rust 编译后的符号名与源码函数名一致，使用蛇形命名可以直接映射，减少额外的名称转换层。</p></li><li><p><strong>提高可读性</strong>：蛇形命名在跨语言调用时更易识别和区分单词边界。</p></li></ol><h2 id="影响范围" tabindex="-1">影响范围 <a class="header-anchor" href="#影响范围" aria-label="Permalink to “影响范围”">​</a></h2><h3 id="核心兼容性问题" tabindex="-1">核心兼容性问题 <a class="header-anchor" href="#核心兼容性问题" aria-label="Permalink to “核心兼容性问题”">​</a></h3><p>由于 ABI 函数名称变更，存在以下<strong>双向不兼容</strong>问题：</p><table tabindex="0"><thead><tr><th>场景</th><th>兼容性</th><th>说明</th></tr></thead><tbody><tr><td>新版接口封装 + 旧版 Golang 库</td><td>❌ 不兼容</td><td>函数名不匹配，无法调用</td></tr><tr><td>旧版接口封装 + 新版 Rust 库</td><td>❌ 不兼容</td><td>函数名不匹配，无法调用</td></tr><tr><td>新版接口封装 + 新版 Rust 库</td><td>✅ 兼容</td><td>官方已全部适配</td></tr></tbody></table><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>如果您之前使用的是 TTHSD Golang，迁移到 TTHSD Next 时必须同时更新：</p><ol><li><strong>动态库</strong>：从 Golang 版本切换到 Rust 版本</li><li><strong>接口封装</strong>：使用新版官方封装</li></ol></div><h3 id="官方接口封装状态" tabindex="-1">官方接口封装状态 <a class="header-anchor" href="#官方接口封装状态" aria-label="Permalink to “官方接口封装状态”">​</a></h3><p>新版接口封装已全部适配完成，支持以下语言：</p><table tabindex="0"><thead><tr><th>语言</th><th>状态</th><th>文档</th></tr></thead><tbody><tr><td>Python</td><td>✅ 已适配</td><td><a href="/Bulletin/back/TTHSD/zh/interface/py/how-to-use.html">Python 接口使用</a></td></tr><tr><td>Golang</td><td>✅ 已适配</td><td><a href="/Bulletin/back/TTHSD/zh/interface/golang/how-to-use.html">Golang 接口使用</a></td></tr><tr><td>TypeScript</td><td>✅ 已适配</td><td><a href="/Bulletin/back/TTHSD/zh/interface/ts/how-to-use.html">TypeScript 接口使用</a></td></tr><tr><td>C/C++/C#</td><td>✅ 已适配</td><td><a href="/Bulletin/back/TTHSD/zh/interface/c_cpp_csharp/how-to-use.html">C/CPP/C# 接口使用</a></td></tr><tr><td>Java/Kotlin</td><td>✅ 已适配</td><td><a href="/Bulletin/back/TTHSD/zh/interface/java_kt/how-to-use.html">Java/Kotlin 接口使用</a></td></tr><tr><td>Rust</td><td>✅ 已适配</td><td><a href="/Bulletin/back/TTHSD/zh/interface/rust/how-to-use.html">Rust 接口使用</a></td></tr><tr><td>Godot</td><td>✅ 已适配</td><td><a href="/Bulletin/back/TTHSD/zh/interface/godot/how-to-use.html">Godot 接口使用</a></td></tr></tbody></table><h2 id="迁移建议" tabindex="-1">迁移建议 <a class="header-anchor" href="#迁移建议" aria-label="Permalink to “迁移建议”">​</a></h2><h3 id="使用官方新版接口封装-推荐" tabindex="-1">使用官方新版接口封装（推荐） <a class="header-anchor" href="#使用官方新版接口封装-推荐" aria-label="Permalink to “使用官方新版接口封装（推荐）”">​</a></h3><p>直接使用官方提供的最新版接口封装，已完全适配新版 Rust 库的蛇形命名风格。</p><h3 id="自行适配-如有自定义封装" tabindex="-1">自行适配（如有自定义封装） <a class="header-anchor" href="#自行适配-如有自定义封装" aria-label="Permalink to “自行适配（如有自定义封装）”">​</a></h3><p>如果您的项目使用自定义封装，需要将所有函数调用名从驼峰改为蛇形：</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 旧版（适配 Golang 库）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lib.getDownloader(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 新版（适配 Rust 库）</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">lib.get_downloader(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="时间线" tabindex="-1">时间线 <a class="header-anchor" href="#时间线" aria-label="Permalink to “时间线”">​</a></h2><ul><li><strong>TTHSD Golang</strong>：使用驼峰命名（<code>getDownloader</code> 等），已停止开发</li><li><strong>TTHSD Next</strong>：使用蛇形命名（<code>get_downloader</code> 等），持续维护</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>ABI 命名风格的变更是 TTHSD Next 迁移到 Rust 后的自然选择，虽然对现有项目有一定迁移成本，但新的命名风格更加规范、统一。建议所有用户使用官方提供的接口封装，以获得最佳兼容性和持续更新支持。</p><hr><p><strong>相关文档</strong>：</p><ul><li><a href="/Bulletin/back/TTHSD/zh/api/API-overview.html">API 概览</a></li><li><a href="/Bulletin/back/TTHSD/zh/guide/getting-started.html">快速开始</a></li></ul>`,28)])])}const b=a(o,[["render",r]]);export{g as __pageData,b as default};
